/**
 * Inline category for a transaction split. If `type` is omitted, the server uses the category kind implied by the
 * parent transaction (`EXPENSE` → expense category, `INCOME` → income category). If `type` is provided, it must
 * match that implied kind.
 *
 */
export type SplitInlineNewCategory = {
    name: string;
    type?: CategoryType;
};

/**
 * Set exactly one of `categoryId`, `newCategoryName`, or `newCategory` to assign a category to the split line.
 * For effective `EXPENSE` transactions with splits, each line must include `budgetId` (envelope) for that split amount.
 *
 */
export type TransactionSplitWrite = {
    categoryId?: string;
    newCategoryName?: string;
    newCategory?: SplitInlineNewCategory;
    /**
     * Required for each split when the parent transaction is an effective expense with splits.
     */
    budgetId?: string;
    amount: number;
    subtitle: string;
};

/**
 * `budgetId` and `splits` are mutually exclusive: if `splits` is non-empty, `budgetId` must be null and each split
 * line carries its own `budgetId` for effective expenses.
 * Top-level `categoryId` / `newCategory` and `splits` are mutually exclusive: if `splits` is non-empty, omit
 * top-level category fields; each split line carries its own category.
 *
 */
export type CreateTransactionRequest = {
    type?: TransactionType;
    /**
     * Used when there are no splits. Must be null when `splits` is non-empty.
     */
    budgetId?: string | null;
    accountId: string;
    categoryId?: string | null;
    transferToAccountId?: string | null;
    /**
     * When set, links this transaction to one occurrence: **bill instance** id if `type` is `EXPENSE`, **income instance**
     * id if `type` is `INCOME`. Must belong to the same household as `accountId`. Omit for `TRANSFER` and for unlinked
     * transactions. See operation description for validation and side effects (stores `transactionId` on the instance;
     * derived `status` on instance responses reflects the link and due/expected instant vs UTC now).
     *
     */
    instanceId?: string | null;
    newCategory?: {
        name: string;
        type: CategoryType;
    };
    name: string;
    amount: number;
    date: string;
    notes?: string | null;
    recipientId?: string | null;
    newRecipientName?: string;
    /**
     * When `type` is `INCOME`, links the transaction to an existing income source (payer). Ignored for other types.
     *
     */
    incomeSourceId?: string | null;
    /**
     * When `type` is `INCOME` and `incomeSourceId` is not set, get-or-create an income source by name in the household.
     * Ignored for other types.
     *
     */
    newIncomeSourceName?: string;
    /**
     * When present and non-empty, top-level `budgetId` and top-level category fields must be unset.
     */
    splits?: Array<TransactionSplitWrite>;
};

/**
 * `budgetId` and `splits` are mutually exclusive: if `splits` is non-empty, `budgetId` must be null.
 * Top-level `categoryId` and `splits` are mutually exclusive: if `splits` is non-empty (after the update),
 * `categoryId` must be null.
 *
 */
export type UpdateTransactionRequest = {
    type?: TransactionType;
    accountId?: string;
    /**
     * Must be null when `splits` is non-empty.
     */
    budgetId?: string | null;
    /**
     * Must be null when the transaction has non-empty `splits` (after this update).
     */
    categoryId?: string | null;
    transferToAccountId?: string | null;
    /**
     * Set or clear (`null`) the linked bill or income instance. Same rules as create: **bill instance** for `EXPENSE`,
     * **income instance** for `INCOME`; must match `type` and household. Changing `type` or clearing the link updates
     * the stored link on the instance when applicable (derived `status` is computed on read). Not valid when `type` is `TRANSFER`.
     *
     */
    instanceId?: string | null;
    name?: string;
    amount?: number;
    date?: string;
    notes?: string | null;
    recipientId?: string | null;
    /**
     * When `type` is `INCOME`, set or clear the linked income source. Ignored for other types.
     */
    incomeSourceId?: string | null;
    /**
     * When present and non-empty, top-level `budgetId` and top-level `categoryId` must be null.
     */
    splits?: Array<TransactionSplitWrite>;
};

export type CloneTransactionRequest = {
    date?: string;
};

/**
 * `budgetId` and `splits` are mutually exclusive: if `splits` is non-empty, `budgetId` must be null and each split
 * may carry its own `budgetId`.
 * Top-level `categoryId` / `newCategoryName` and `splits` are mutually exclusive: if `splits` is non-empty, omit
 * top-level category fields; each split line carries its own category.
 *
 */
export type CreateBillRequest = {
    name: string;
    recipientId?: string;
    newRecipientName?: string;
    accountId: string;
    /**
     * Used when there are no splits. Must be null when `splits` is non-empty.
     */
    budgetId?: string | null;
    /**
     * Timezone-aware instant; prefer UTC (`Z`), or offset local start-of-day if needed (see `BillInstance.dueDate`).
     */
    dueDate: string;
    recurrenceType: RecurrenceType;
    customIntervalDays?: number;
    estimatedAmount: number;
    endDate?: string | null;
    lastPaymentDate?: string;
    /**
     * Optional; omit to leave unset, or set to null explicitly to store no handling.
     */
    paymentHandling?: BillPaymentHandling | null;
    categoryId?: string;
    newCategoryName?: string;
    /**
     * When present and non-empty, top-level `budgetId` and top-level category fields must be unset.
     */
    splits?: Array<BillSplitWrite>;
};

/**
 * `budgetId` and `splits` are mutually exclusive: if `splits` is non-empty, `budgetId` must be null.
 * Top-level `categoryId` and `splits` are mutually exclusive: if `splits` is non-empty (after the update),
 * `categoryId` must be null.
 * **`updateScope`**: **ALL** applies immediately (omit **`fromDate`**; do not send **`recurrenceType`** or **`customIntervalDays`**).
 * **UPCOMING** requires **`fromDate`** and schedules changes without updating the blueprint row until they mature.
 *
 */
export type UpdateBillRequest = {
    updateScope: BlueprintPatchScope;
    /**
     * Required when **`updateScope`** is **UPCOMING**; must be omitted when **ALL**.
     */
    fromDate?: string;
    name?: string;
    recipientId?: string;
    newRecipientName?: string;
    accountId?: string;
    /**
     * Must be null when `splits` is non-empty.
     */
    budgetId?: string | null;
    /**
     * Timezone-aware instant; prefer UTC (`Z`), or offset local start-of-day if needed (see `BillInstance.dueDate`).
     */
    dueDate?: string;
    recurrenceType?: RecurrenceType;
    customIntervalDays?: number;
    estimatedAmount?: number;
    endDate?: string | null;
    lastPaymentDate?: string | null;
    /**
     * Set or clear payment handling; omit to leave unchanged.
     */
    paymentHandling?: BillPaymentHandling | null;
    /**
     * Must be null when the bill has non-empty `splits` (after this update).
     */
    categoryId?: string | null;
    archived?: boolean;
    /**
     * When present and non-empty, top-level `budgetId` and top-level `categoryId` must be null.
     */
    splits?: Array<BillSplitWrite>;
};

export type ArchiveBillRequest = {
    archived: boolean;
};

/**
 * Updates **only** the targeted bill instance (never other occurrences).
 *
 * **`recipient`** vs **`newRecipientName`**: mutually exclusive — send at most one. When **`newRecipientName`** is set,
 * the server get-or-creates a recipient in the household (same as create bill).
 *
 * **`categoryId`** vs **`newCategoryName`**: mutually exclusive when used. Neither may be sent when the instance
 * effectively has split lines: non-empty **`splits`** in this request, existing per-instance split lines, or the parent
 * bill has blueprint split lines.
 *
 * **`budgetId`** and **`splits`**: if **`splits`** is non-empty, **`budgetId`** must be null (each split line may carry
 * its own **`budgetId`**). When **`splits`** is present and empty, per-instance split overrides are removed and the
 * instance **`categoryId`** / **`budgetId`** are reset from the current parent bill.
 *
 * **`paymentHandling`**: omit to leave the instance override unchanged; send **`null`** to clear the override (inherit
 * from the parent bill); send an enum value to set an instance-specific override.
 *
 */
export type UpdateBillInstanceRequest = {
    name?: string;
    /**
     * Existing recipient id; omit when using **`newRecipientName`**.
     */
    recipient?: string;
    /**
     * Get-or-create recipient by name; omit when using **`recipient`**.
     */
    newRecipientName?: string;
    amount?: number;
    /**
     * Timezone-aware instant; prefer UTC (`Z`), or offset local start-of-day if needed (see `BillInstance.dueDate`).
     */
    dueDate?: string;
    accountId?: string;
    /**
     * Used when there are no split lines on the instance. Must be null when **`splits`** is non-empty.
     */
    budgetId?: string | null;
    /**
     * Must be omitted when **`newCategoryName`** is set or when split lines apply.
     */
    categoryId?: string;
    /**
     * Create a new **EXPENSE** category by name; omit when **`categoryId`** is set.
     */
    newCategoryName?: string;
    /**
     * Set, clear, or leave unchanged; see schema description above.
     */
    paymentHandling?: BillPaymentHandling | null;
    /**
     * When present and non-empty, top-level **`budgetId`** and top-level category fields must be unset.
     * When present and **empty**, per-instance split overrides are removed and **`categoryId`** / **`budgetId`** are reset
     * from the parent bill; do not send top-level **`categoryId`**, **`newCategoryName`**, or **`budgetId`** in the same request.
     *
     */
    splits?: Array<BillSplitWrite>;
};

/**
 * Updates **only** the targeted income instance (never other occurrences).
 * `categoryId` vs `newCategoryName`, and `incomeSourceId` vs `newIncomeSourceName`, are mutually exclusive: send at most
 * one from each pair. When `newCategoryName` is set, the server creates an **INCOME** category and links it to **all**
 * budgets in the household (same default linking as `CreateCategoryRequest` with `budgetIds` omitted).
 *
 */
export type UpdateIncomeInstanceRequest = {
    name?: string;
    amount?: number;
    /**
     * Timezone-aware instant; prefer UTC (`Z`), or offset local start-of-day if needed (see `IncomeInstance.expectedDate`).
     */
    expectedDate?: string;
    accountId?: string;
    /**
     * Must be omitted when `newCategoryName` is set.
     */
    categoryId?: string;
    /**
     * Create a new **INCOME** category by name; must be omitted when `categoryId` is set.
     */
    newCategoryName?: string;
    /**
     * Must be omitted when `newIncomeSourceName` is set.
     */
    incomeSourceId?: string;
    /**
     * Get-or-create an income source by name in the household; must be omitted when `incomeSourceId` is set.
     */
    newIncomeSourceName?: string;
};

